import { task, retry } from "@trigger.dev/sdk/v3";

export const unreliableFetchTask = task({
  id: "unreliable-fetch-task_with_retries__dXVixAi",
  retry: {
    maxAttempts: 5,
    minTimeoutInMs: 1000,
    maxTimeoutInMs: 10000,
    factor: 2,
  },
  run: async (payload: any) => {
    const response = await retry.fetch("https://httpbin.org/status/500,200", {
      method: "GET",
      retry: {
        maxAttempts: 5,
        minTimeoutInMs: 1000,
        maxTimeoutInMs: 10000,
        factor: 2,
      },
    });

    return {
      status: response.status,
      ok: response.ok,
    };
  },
});

